            UPDATE public.utm_visualization
      SET aggregation= $$
{
  "metrics": [
    {
      "id": "1",
      "aggregation": "COUNT",
      "field": "",
      "customLabel": ""
    }
  ],
  "bucket": {
    "id": "1000",
    "aggregation": "TERMS",
    "type": "BUCKET",
    "field": "@timestamp",
    "customLabel": "Date",
    "subBucket": {
      "id": "1002",
      "aggregation": "TERMS",
      "type": "BUCKET",
      "field": "origin.ip.keyword",
      "customLabel": "Client IP Address",
      "subBucket": {
        "id": "1004",
        "aggregation": "TERMS",
        "type": "BUCKET",
        "field": "log.MailboxOwnerUPN.keyword",
        "customLabel": "Mailbox Owner UPN",
        "subBucket": {
          "id": "1005",
          "aggregation": "TERMS",
          "type": "BUCKET",
          "field": "action.keyword",
          "customLabel": "Operation",
          "subBucket": {
            "id": "1007",
            "aggregation": "TERMS",
            "type": "BUCKET",
            "field": "actionResult.keyword",
            "customLabel": "Result Status",
            "terms": {
              "sortBy": "_count",
              "asc": false,
              "size": 5
            }
          },
          "terms": {
            "sortBy": "_count",
            "asc": false,
            "size": 5
          }
        },
        "terms": {
          "sortBy": "_count",
          "asc": false,
          "size": 5
        }
      },
      "terms": {
        "sortBy": "_count",
        "asc": false,
        "size": 5
      }
    },
    "terms": {
      "sortBy": "_count",
      "asc": false,
      "size": 5
    }
  }
}
      $$
            WHERE id = 837;
